const items = $input.all();

// 如果输入是空数组或者仅包含空对象，返回数量为0的信息
if (items.length === 0 || items.every(item => Object.keys(item.json || {}).length === 0)) {
    console.log('Returning early with count 0 due to empty input or input containing only empty objects');
    return [{
        json: {
            组装段汇总信息: {
                今日工单总数量: 0,
                累计完成数量: 0,
                今日完成数量: 0,
                未完成数量: 0
            }
        }
    }];
}

const result = {};
let overallCompletedCount = 0;
let overallOrderQuantity = 0;
let overallDayCompletedCount = 0;
const uniqueJobOrders = new Map();

for (const item of items) {
    console.log('Processing item:', JSON.stringify(item, null, 2));
    if (item.json && Object.keys(item.json).length > 0) {
        const productModelName = item.json.product_model_name || "未知机型";
        const jobOrderNumber = item.json.joborder_number || "未知工单号";
        const productQuantity = item.json.product_quantity || 0;
        const totalCompletedCount = parseInt(item.json.total_completed_count) || 0;

        if (!result[productModelName]) {
            result[productModelName] = {
                joborders: {},
                total_count: 0,
                total_completed_count: 0,
                total_day_completed_count: 0
            };
        }

        if (!result[productModelName].joborders[jobOrderNumber]) {
            result[productModelName].joborders[jobOrderNumber] = {
                total_quantity: productQuantity,
                complete_count: 0,
                day_completed_count: 0
            };

            result[productModelName].total_count += productQuantity;
            overallOrderQuantity += productQuantity;
        }

        // 增加今日完成数量
        result[productModelName].joborders[jobOrderNumber].day_completed_count += 1;

        // 确保同一工单的累计完成数只计算一次
        if (!uniqueJobOrders.has(jobOrderNumber)) {
            uniqueJobOrders.set(jobOrderNumber, true);
            result[productModelName].joborders[jobOrderNumber].complete_count = totalCompletedCount;
            result[productModelName].total_completed_count += totalCompletedCount;
            overallCompletedCount += totalCompletedCount;
        }

        // 增加“今日完成数量”到总计
        result[productModelName].total_day_completed_count += 1;
        overallDayCompletedCount += 1;
    }
}

const overallUncompletedCount = overallOrderQuantity - overallCompletedCount;

const overallSummary = {
    组装段汇总信息: {
        今日工单总数量: overallOrderQuantity,
        累计完成数量: overallCompletedCount,
        今日完成数量: overallDayCompletedCount,
        未完成数量: overallUncompletedCount
    }
};

const output = [overallSummary].concat(Object.entries(result).map(([productModelName, data]) => ({
    机型: productModelName,
    总数量: data.total_count,
    累计完成数量: data.total_completed_count,
    今日完成数量: data.total_day_completed_count,
    未完成数量: data.total_count - data.total_completed_count,
    具体完成情况: Object.entries(data.joborders).map(([jobOrderNumber, counts]) => ({
        工单号: jobOrderNumber,
        总数量: counts.total_quantity,
        累计完成数量: counts.complete_count,
        今日完成数量: counts.day_completed_count,
        未完成数量: counts.total_quantity - counts.complete_count
    }))
})));

return output.map(data => ({ json: data }));

