const items = $input.all();

// 获取当前日期并减去一天
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(now.getDate() - 1);
const formattedDate = `${yesterday.getFullYear()}-${String(yesterday.getMonth() + 1).padStart(2, '0')}-${String(yesterday.getDate()).padStart(2, '0')}`;

let htmlContent = `
<style>
    body { font-family: Arial, sans-serif; color: #333; margin: 20px; line-height: 1.4; }
    .header { display: flex; align-items: center; justify-content: center; gap: 8px; margin-bottom: 20px; }
    .icon { width: 68px; height: 60px; background-image: url(data:image/png;base64,); background-size: 100% 100%; background-repeat: no-repeat; }
    .text { font-family: Arial, sans-serif; font-size: 32px; font-weight: 900; color: #000; letter-spacing: -0.5px; white-space: nowrap; }
    .total-count { color: #d9534f; font-weight: bold; }
    .completed-count { color: #5cb85c; font-weight: bold; }
    .unfinished-count { color: #f0ad4e; font-weight: bold; }
    h2 { background-color: #f8f9fa; padding: 10px; border-left: 4px solid #007bff; margin-top: 20px; margin-bottom: 10px; margin-left: 20px; }
    .summary-info { font-size: 18px; margin-bottom: 15px; padding: 10px; background-color: #f0f4f8; border-left: 4px solid #5bc0de; margin-left: 20px; }
    .model-info { margin: 20px 0 5px; color: #007bff; font-weight: bold; font-size: 16px; margin-left: 20px; }
    .model-details { font-size: 15px; color: #555; margin-bottom: 10px; padding: 8px; background-color: #e9ecef; margin-left: 20px; }
    ul { padding: 0 0 0 45px; list-style-type: none; margin: 0; }
    li { padding: 4px 0; margin-bottom: 4px; background-color: #f9f9f9; font-size: 14px; }
    li span { margin-right: 20px; }
</style>

<div class="header">
  <div class="icon"></div>
  <h1 class="text">生产日报 (${formattedDate})</h1>
</div>`;

let currentSegment = "";

items.forEach(item => {
    if (item.json.组装段汇总信息) {
        currentSegment = "组装段";
        htmlContent += `<h2>${currentSegment}</h2>`;
        htmlContent += `<p class="summary-info">今日工单总数量: <span class="total-count">${item.json.组装段汇总信息.今日工单总数量}</span>，累计完成数量: <span class="completed-count">${item.json.组装段汇总信息.累计完成数量}</span>，今日完成数量: <span class="completed-count">${item.json.组装段汇总信息.今日完成数量}</span>，未完成数量: <span class="unfinished-count">${item.json.组装段汇总信息.未完成数量}</span></p>`;
    } else if (item.json.包装段汇总信息) {
        currentSegment = "包装段";
        htmlContent += `<h2>${currentSegment}</h2>`;
        htmlContent += `<p class="summary-info">今日工单总数量: <span class="total-count">${item.json.包装段汇总信息.今日工单总数量}</span>，累计完成数量: <span class="completed-count">${item.json.包装段汇总信息.累计完成数量}</span>，今日完成数量: <span class="completed-count">${item.json.包装段汇总信息.今日完成数量}</span>，未完成数量: <span class="unfinished-count">${item.json.包装段汇总信息.未完成数量}</span></p>`;
    } else {
        if (currentSegment) {
            htmlContent += `<div class="model-info">机型: ${item.json.机型}</div>`;
            htmlContent += `<p class="model-details">机型总数量: <span class="total-count">${item.json.总数量}</span>，累计完成数量: <span class="completed-count">${item.json.累计完成数量}</span>，今日完成数量: <span class="completed-count">${item.json.今日完成数量}</span>，未完成数量: <span class="unfinished-count">${item.json.未完成数量}</span></p>`;
            htmlContent += '<ul>';
            item.json.具体完成情况.forEach(detail => {
                htmlContent += `<li>
                                  <span>工单号: ${detail.工单号}</span>
                                  <span>总: <span class="total-count">${detail.总数量}</span></span>
                                  <span>累计完成: <span class="completed-count">${detail.累计完成数量}</span></span>
                                  <span>今日完成: <span class="completed-count">${detail.今日完成数量}</span></span>
                                  <span>未完成: <span class="unfinished-count">${detail.未完成数量}</span></span>
                                </li>`;
            });
            htmlContent += '</ul>';
        }
    }
});

// 返回格式化的 HTML 邮件内容
return [{ json: { html: htmlContent } }];
